from typing import Iterable, List, Sequence, Optional, Any, Union, Literal

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage

from psanp.classifiers.sequence_classifier import SequenceClassifier


def _parse_classes(obj: Any) -> List[str]:
    if isinstance(obj, str):
        return obj.split()
    if hasattr(obj, "__iter__") and all(isinstance(o, str) for o in obj):
        return list(obj)
    else:
        raise ValueError(f"Unsupported value for 'classes': {obj}")


def _parse_input_classes(obj: Any) -> Union[List[str], Literal["all"], None]:
    if obj is None or obj == "all":
        return obj
    return _parse_classes(obj)


class ClassSelectorStage(SequenceClassifier):
    """A ``Stage`` that:

        - Select the points of a point cloud that match the classes given by the user
        - Applies stages to the selected points
        - Reprojects the resulting classification to the selected points

    .. warning::

        The stages defined in this stage must not modify the number of points of the
        input point cloud, nor modify their order
    """

    def __init__(
        self,
        classes: Iterable[str] = (),
        stages: Sequence[Stage] = (),
        filter_input: bool = True,
        blacklist: bool = False,
        stage_name: Optional[str] = None,
    ) -> None:
        super().__init__(stages, stage_name)
        self.classes = list(classes)
        self.filter_input = filter_input
        self.blacklist = blacklist

    @classmethod
    def options(cls) -> List[Option]:
        return [
            *super().options(),
            Option(
                "classes",
                description="The class names of the input point cloud that"
                "are going to be reassigned with the values. "
                "Those classes must be defined in the classification codes of "
                "the pipeline.",
                type_cast=_parse_classes,
                required=True,
            ),
            Option(
                "filter_input",
                description="Indicate if the `classes` option should also select the "
                "points before sending them to the stages. If set to false, the whole "
                "point cloud is sent to the stages, and the `classes` selection is "
                "only applied after the stages are executed",
                type_cast=bool,
                required=False,
            ),
            Option(
                "blacklist",
                description="Invert the selection: all the points are selected except "
                "the ones that have a class listed in `classes`.",
                type_cast=bool,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        class_ids = [
            pipeline_metadata.classification_codes[class_name]
            for class_name in self.classes
        ]
        mask = np.isin(cloud.classification, class_ids)
        if self.blacklist:
            mask = ~mask
        if self.filter_input:
            selected_cloud = cloud[mask]
        else:
            # Using the whole cloud without copy for performance:
            selected_cloud = cloud
            # Saving the original classification to restore it later, because
            # the stages mights modify it as a side effect
            saved_classification = cloud.classification.copy()
        clouds = list(super().execute_on(selected_cloud, pipeline_metadata))
        if len(clouds) != 1:
            raise ValueError(
                f"The '{self.__class__.__name__}' only support stages "
                "that return a single point cloud"
            )
        output_cloud = clouds[0]
        if len(output_cloud) != len(selected_cloud):
            raise ValueError(
                f"Output point cloud ({len(output_cloud)} points) does not have the "
                f"same number of points as the input ({len(selected_cloud)} points). "
                "Has any of the following stages removed or added points?\n"
                f"{[stage.__class__.__name__ for stage in self.stages]}"
            )
        if self.filter_input:
            cloud.classification[mask] = output_cloud.classification[:]
        else:
            saved_classification[mask] = output_cloud.classification[mask]
            cloud.fields["classification"] = saved_classification
        return (cloud,)
